const { Manifold, CrossSection, setCircularSegments } = api;

const N = 48;
setCircularSegments(N);

const sph = (p, r) => Manifold.sphere(r, N).translate(p);
const capsule = (p1, r1, p2, r2) => sph(p1, r1).add(sph(p2, r2)).hull();

function buildFinger(spec) {
  const { xBase, yBase, zBase, lengths, radii, curlPerJoint, sideTilt = 0, knuckleScale = 1.25 } = spec;
  let x = xBase, y = yBase, z = zBase;
  let pitch = 0;
  const points = [{ x, y, z, r: radii[0] * knuckleScale }];
  for (let i = 0; i < lengths.length; i++) {
    pitch += curlPerJoint;
    const Pr = pitch * Math.PI / 180;
    const Sr = sideTilt * Math.PI / 180;
    x += lengths[i] * Math.sin(Sr) * Math.cos(Pr);
    y += lengths[i] * Math.sin(Pr);
    z += lengths[i] * Math.cos(Pr);
    const isTip = i === lengths.length - 1;
    const r = isTip ? radii[i + 1] : radii[i + 1] * knuckleScale;
    points.push({ x, y, z, r });
  }
  let f = null;
  for (let i = 0; i < points.length - 1; i++) {
    const a = points[i], b = points[i + 1];
    const seg = capsule([a.x, a.y, a.z], a.r, [b.x, b.y, b.z], b.r);
    f = f ? f.add(seg) : seg;
  }
  return { mesh: f, points, pitchAtTip: pitch };
}

// Manifold's rotate([θ,0,0]) maps (0,0,1) → (0, sin θ, cos θ).
// To map +Z to dorsalDir = (0, -cosP, sinP), need sin θ = -cosP and cos θ = sinP → θ = pitchDeg - 90.
function buildNail(dipP, tipP, pitchDeg, fingerR) {
  const t = 0.55;
  const mx = dipP.x + (tipP.x - dipP.x) * t;
  const my = dipP.y + (tipP.y - dipP.y) * t;
  const mz = dipP.z + (tipP.z - dipP.z) * t;
  const Pr = pitchDeg * Math.PI / 180;
  const segLen = Math.hypot(tipP.y - dipP.y, tipP.z - dipP.z);

  function roundRect(w, d, r, segs) {
    const pts = [];
    const cx = w/2 - r, cy = d/2 - r;
    const corners = [[cx,cy,0],[-cx,cy,Math.PI/2],[-cx,-cy,Math.PI],[cx,-cy,3*Math.PI/2]];
    for (const [x, y, a0] of corners) {
      for (let i = 0; i <= segs; i++) {
        const a = a0 + (i / segs) * (Math.PI / 2);
        pts.push([x + r*Math.cos(a), y + r*Math.sin(a)]);
      }
    }
    return CrossSection.ofPolygons([pts]);
  }

  const halfW = fingerR * 0.78;
  const halfL = segLen * 0.45;
  const cornerR = Math.min(halfW, halfL) * 0.45;
  const thickness = 1.6;
  const cs = roundRect(halfW * 2, halfL * 2, cornerR, 8);
  let nail = cs.extrude(thickness, 0, 0, 1, true);
  nail = nail.rotate([pitchDeg - 90, 0, 0]);

  const offset = fingerR + 0.05;
  const cy = my - Math.cos(Pr) * offset;
  const cz = mz + Math.sin(Pr) * offset;
  nail = nail.translate([mx, cy, cz]);
  return nail;
}

const wristBottom = Manifold.cylinder(20, 13.5, 11.0, N);
const palmHalfX = 17, palmHalfY = 7.0, handBaseZ = 18, handTopZ = 38;
const handLow  = Manifold.sphere(1, N).scale([palmHalfX * 0.72, palmHalfY * 0.95, 6]).translate([0, -0.5, handBaseZ + 4]);
const handHigh = Manifold.sphere(1, N).scale([palmHalfX * 1.0, palmHalfY * 1.0, 5.5]).translate([0, -1.0, handTopZ - 2]);
let handBody = handLow.add(handHigh).hull();
const palmCup = Manifold.sphere(13, N).scale([1.4, 1.0, 1.15]).translate([0, palmHalfY + 9.5, (handBaseZ + handTopZ) / 2 + 1]);
handBody = handBody.subtract(palmCup);
const thenar = Manifold.sphere(1, N).scale([5.5, 4.0, 8.0]).translate([10, 1.5, 23]);

const mcpZ = 36, mcpY = -1.0;
const fingerSpecs = [
  { xBase:  10.4, yBase: mcpY, zBase: mcpZ, lengths: [16, 11, 9],  radii: [3.0, 2.7, 2.4, 1.9], curlPerJoint: 9,  sideTilt: -3 },
  { xBase:   3.4, yBase: mcpY, zBase: mcpZ, lengths: [18, 13, 10], radii: [3.2, 2.9, 2.5, 2.0], curlPerJoint: 8,  sideTilt:  0 },
  { xBase:  -3.4, yBase: mcpY, zBase: mcpZ, lengths: [16, 12, 9],  radii: [3.0, 2.7, 2.4, 1.9], curlPerJoint: 9,  sideTilt:  3 },
  { xBase: -10.4, yBase: mcpY, zBase: mcpZ, lengths: [13,  9, 7],  radii: [2.7, 2.4, 2.1, 1.6], curlPerJoint: 11, sideTilt:  6 },
];
const fingerResults = fingerSpecs.map(buildFinger);
const nailResults = fingerResults.map((fr, i) => buildNail(fr.points.at(-2), fr.points.at(-1), fr.pitchAtTip, fingerSpecs[i].radii.at(-1)));
const thumbSpec = { xBase: 13.5, yBase: 2.5, zBase: 24, lengths: [12, 10], radii: [3.6, 3.1, 2.6, 2.0], curlPerJoint: 18, sideTilt: -24 };
const thumbResult = buildFinger(thumbSpec);
const thumbNail = buildNail(thumbResult.points.at(-2), thumbResult.points.at(-1), thumbResult.pitchAtTip, thumbSpec.radii.at(-1));

let hand = wristBottom.add(handBody).add(thenar);
for (const fr of fingerResults) hand = hand.add(fr.mesh);
hand = hand.add(thumbResult.mesh);
for (const n of nailResults) hand = hand.add(n);
hand = hand.add(thumbNail);
return hand;
